// This is a simple interface which specifies echo.Route addition functions which
// are present on both echo.Echo and echo.Group, since we want to allow using
// either of them for path registration
type EchoRouter interface {
	CONNECT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) echo.RouteInfo
	DELETE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) echo.RouteInfo
	GET(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) echo.RouteInfo
	HEAD(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) echo.RouteInfo
	OPTIONS(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) echo.RouteInfo
	PATCH(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) echo.RouteInfo
	POST(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) echo.RouteInfo
	PUT(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) echo.RouteInfo
	TRACE(path string, h echo.HandlerFunc, m ...echo.MiddlewareFunc) echo.RouteInfo
}

// RegisterHandlers adds each server route to the EchoRouter.
func RegisterHandlers(router EchoRouter, si ServerInterface) {
	RegisterHandlersWithBaseURL(router, si, "")
}

// Registers handlers, and prepends BaseURL to the paths, so that the paths
// can be served under a prefix.
func RegisterHandlersWithBaseURL(router EchoRouter, si ServerInterface, baseURL string) {

	wrapper := ServerInterfaceWrapper{
		Handler: si,
	}

	router.GET(baseURL+"/assignments", wrapper.GetAssignments)
	router.POST(baseURL+"/assignments", wrapper.PostAssignments)
	router.DELETE(baseURL+"/assignments/:assignmentId", wrapper.DeleteAssignmentsAssignmentId)
	router.GET(baseURL+"/assignments/:assignmentId", wrapper.GetAssignmentsAssignmentId)
	router.PATCH(baseURL+"/assignments/:assignmentId", wrapper.PatchAssignmentsAssignmentId)
	router.POST(baseURL+"/auth/login", wrapper.PostAuthLogin)
	router.POST(baseURL+"/auth/logout", wrapper.PostAuthLogout)
	router.GET(baseURL+"/auth/me", wrapper.GetAuthMe)
	router.POST(baseURL+"/auth/register", wrapper.PostAuthRegister)
	router.GET(baseURL+"/courses", wrapper.GetCourses)
	router.POST(baseURL+"/courses", wrapper.PostCourses)
	router.DELETE(baseURL+"/courses/:courseId", wrapper.DeleteCoursesCourseId)
	router.GET(baseURL+"/courses/:courseId", wrapper.GetCoursesCourseId)
	router.PATCH(baseURL+"/courses/:courseId", wrapper.PatchCoursesCourseId)
	router.GET(baseURL+"/notes", wrapper.GetNotes)
	router.POST(baseURL+"/notes", wrapper.PostNotes)
	router.DELETE(baseURL+"/notes/:noteId", wrapper.DeleteNotesNoteId)
	router.GET(baseURL+"/notes/:noteId", wrapper.GetNotesNoteId)
	router.PATCH(baseURL+"/notes/:noteId", wrapper.PatchNotesNoteId)
	router.GET(baseURL+"/users", wrapper.GetUsers)
	router.DELETE(baseURL+"/users/:userId", wrapper.DeleteUsersUserId)
	router.GET(baseURL+"/users/:userId", wrapper.GetUsersUserId)
	router.PATCH(baseURL+"/users/:userId", wrapper.PatchUsersUserId)
	router.GET(baseURL+"/workspaces", wrapper.GetWorkspaces)
	router.POST(baseURL+"/workspaces", wrapper.PostWorkspaces)
	router.DELETE(baseURL+"/workspaces/:workspaceId", wrapper.DeleteWorkspacesWorkspaceId)
	router.GET(baseURL+"/workspaces/:workspaceId", wrapper.GetWorkspacesWorkspaceId)
	router.PATCH(baseURL+"/workspaces/:workspaceId", wrapper.PatchWorkspacesWorkspaceId)
	router.GET(baseURL+"/workspaces/:workspaceId/courses", wrapper.GetWorkspacesWorkspaceIdCourses)

}

